# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, render_template, request

app = Flask(__name__)

@app.route('/')
def welcome_dashboard():
    # Get query parameters with default values
    user_name = request.args.get('name', 'Guest')
    user_bio = request.args.get('bio', 'No bio provided')
    user_location = request.args.get('location', 'Unknown')
    user_status = request.args.get('status', 'No status message')
    
    # Simple HTML escaping for security
    def escape_html(text):
        return text.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')
    
    # Process bio and status for basic formatting
    processed_bio = user_bio.replace('\n', '<br>')
    processed_status = user_status.replace('\n', '<br>')
    
    # Convert basic markdown-like formatting to HTML
    processed_bio = processed_bio.replace('**', '<strong>').replace('__', '<strong>')
    processed_bio = processed_bio.replace('*', '<em>').replace('_', '<em>')
    processed_bio = processed_bio.replace('</strong>', '</strong>')
    processed_bio = processed_bio.replace('</em>', '</em>')
    
    processed_status = processed_status.replace('**', '<strong>').replace('__', '<strong>')
    processed_status = processed_status.replace('*', '<em>').replace('_', '<em>')
    processed_status = processed_status.replace('</strong>', '</strong>')
    processed_status = processed_status.replace('</em>', '</em>')
    
    return render_template('dashboard.html', 
                         user_name=user_name,
                         user_bio=processed_bio,
                         user_location=user_location,
                         user_status=processed_status)

if __name__ == '__main__':
    app.run(debug=True)